var e=[{id:`L3_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`사령관님...... 사령관님!`,JPN:`司令官……司令官！`,ENG:`Commander... Commander!`,TWN:`司令官……司令官！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`으음......`,JPN:`ううむ……`,ENG:`Mm...`,TWN:`嗯……`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`사령관님, 정신이 드십니까?`,JPN:`司令官、気がつきましたか？`,ENG:`Commander, are you awake?`,TWN:`司令官大人，您醒過來了嗎？`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`도미닉......?`,JPN:`ドミニーク……？`,ENG:`Dominic?`,TWN:`多明尼克？`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`내가...... 얼마나 쓰러져 있었지?`,JPN:`私は……どのくらい倒れていたんだ？`,ENG:`How... How long was I out?`,TWN:`我……我昏睡多久了？`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`이틀 정도입니다.`,JPN:`二日くらいです。`,ENG:`A couple of days.`,TWN:`兩天左右。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`이틀이나? 으윽......!!`,JPN:`二日も？　ううっ……！！`,ENG:`A couple of days?! Ugh!`,TWN:`兩天？唔……！！`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`무리하지 마십시오. 부상이 심합니다.`,JPN:`ご無理なさらず。ひどいケガをされています。`,ENG:`Don't strain yourself. You're badly wounded.`,TWN:`請不要太勉強。您受了很重的傷。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`밖은...... 상황은 어떻지?`,JPN:`外は……どんな状況だ？`,ENG:`The outside... What's the situation?`,TWN:`外面……情況如何。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`별로 다를 건 없습니다.`,JPN:`特に変わりません。`,ENG:`Nothing much has changed.`,TWN:`沒什麼特別不同的。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`게임은 여전히 진행 중이고......`,JPN:`ゲームは続いていて……`,ENG:`The game is still in progress,`,TWN:`遊戲仍在持續著。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`클리포트의 마왕들이 접근하는 걸 최대한 저지하는 중입니다.`,JPN:`クリフォトの魔王どもの接近をできる限り阻止しているところです。`,ENG:`and we're doing our best to keep the Demon Lords of Qliphoth at bay.`,TWN:`我們正儘可能地阻止逆卡巴拉魔王們接近。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`......벌써 여기까지 왔나 보군요.`,JPN:`……もうここまでたどり着いたようですね。`,ENG:`It seems they're here already.`,TWN:`……看來它們已經到這裡了啊。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`일단은 제가 막아 보지요.`,JPN:`ひとまずここは俺が阻止します。`,ENG:`I'll try to stop them.`,TWN:`總之我去試著阻擋它們吧。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`......부탁하네.`,JPN:`……頼むぞ。`,ENG:`Thank you.`,TWN:`……拜託你了。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`별말씀을.`,JPN:`お任せを。`,ENG:`You're welcome.`,TWN:`這沒什麼。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`그보다 할 말이 있으면 빨리 마치는 게 좋을 겁니다.`,JPN:`それより、話したいことがあれば早く済ませたほうが良いと思います。`,ENG:`By the way, if you have something to say, you'd better say it now.`,TWN:`比起這個，如果有什麼要說的話，最好還是快說吧。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`오래 버티지는 못할 것 같으니까요.`,JPN:`そう長くは持ちこたえられないはずですから。`,ENG:`I doubt I can last too long.`,TWN:`感覺你也撐不了多久了。`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SS_DELTA_02`,slots:{L:null,C:null,R:null}}}];export{e as default};